fn workspace_detail_matches(project_root: Option<&Path>, detail: &SkillDetailRecord) -> bool {
    let Some(project_root) = project_root else {
        return true;
    };
    detail.scope == Scope::AgentProject.as_str()
        || detail.path.starts_with(project_root)
        || detail.display_path.starts_with(project_root)
}

fn workspace_status_for_score(score: u8) -> &'static str {
    match score {
        80..=100 => "ready",
        45..=79 => "partial",
        _ => "blocked",
    }
}

fn workspace_status_counts<'a>(
    statuses: impl IntoIterator<Item = &'a str>,
) -> (usize, usize, usize) {
    let mut ready = 0usize;
    let mut partial = 0usize;
    let mut blocked = 0usize;
    for status in statuses {
        match status {
            "ready" => ready += 1,
            "partial" => partial += 1,
            _ => blocked += 1,
        }
    }
    (ready, partial, blocked)
}

fn workspace_capability_rows(
    expected_capabilities: &[String],
    taxonomy: &CapabilityTaxonomyResult,
) -> Vec<WorkspaceReadinessCapabilityRow> {
    let expected_keys = expected_capabilities
        .iter()
        .map(|capability| capability_key(capability))
        .collect::<BTreeSet<_>>();
    let mut rows = taxonomy
        .coverage_rows
        .iter()
        .map(|coverage| {
            let expected = expected_keys.is_empty()
                || expected_keys.contains(&capability_key(&coverage.domain_name))
                || expected_keys.contains(&coverage.domain_key);
            let blocker_notes = if coverage.routing_ambiguity != "low" {
                vec![format!(
                    "`{}` has routing ambiguity signals.",
                    redact_for_llm_preview(&coverage.domain_name)
                )]
            } else if coverage.duplicates_redundancy != "low" {
                vec![format!(
                    "`{}` has duplicate or redundancy signals.",
                    redact_for_llm_preview(&coverage.domain_name)
                )]
            } else {
                Vec::new()
            };
            WorkspaceReadinessCapabilityRow {
                capability: coverage.domain_name.clone(),
                domain_key: coverage.domain_key.clone(),
                domain_name: coverage.domain_name.clone(),
                status: workspace_status_for_score(coverage.coverage_score),
                coverage_level: coverage.coverage_level,
                coverage_score: coverage.coverage_score,
                expected,
                skill_count: coverage.skill_count,
                enabled_skill_count: coverage.enabled_skill_count,
                agent_count: coverage.agent_count,
                gap_notes: coverage.gaps.clone(),
                blocker_notes,
                evidence_refs: coverage.evidence_refs.clone(),
            }
        })
        .collect::<Vec<_>>();

    for expected in expected_capabilities {
        let key = capability_key(expected);
        if rows
            .iter()
            .any(|row| row.domain_key == key || capability_key(&row.capability) == key)
        {
            continue;
        }
        rows.push(WorkspaceReadinessCapabilityRow {
            capability: expected.clone(),
            domain_key: key.clone(),
            domain_name: expected.clone(),
            status: "blocked",
            coverage_level: "gap",
            coverage_score: 0,
            expected: true,
            skill_count: 0,
            enabled_skill_count: 0,
            agent_count: 0,
            gap_notes: vec![format!(
                "Expected capability `{}` has no matching local capability-domain evidence.",
                redact_for_llm_preview(expected)
            )],
            blocker_notes: vec![format!(
                "Expected capability `{}` is not covered by visible local skills.",
                redact_for_llm_preview(expected)
            )],
            evidence_refs: Vec::new(),
        });
    }
    rows.sort_by(|left, right| {
        right
            .expected
            .cmp(&left.expected)
            .then_with(|| right.coverage_score.cmp(&left.coverage_score))
            .then_with(|| left.domain_name.cmp(&right.domain_name))
    });
    rows
}

fn capability_key(value: &str) -> String {
    value
        .to_ascii_lowercase()
        .chars()
        .map(|ch| if ch.is_ascii_alphanumeric() { ch } else { '-' })
        .collect::<String>()
        .split('-')
        .filter(|part| !part.is_empty())
        .collect::<Vec<_>>()
        .join("-")
}

#[allow(clippy::too_many_arguments)]
fn workspace_checklist_rows(
    filters: &WorkspaceReadinessFilters,
    visible_details: &[SkillDetailRecord],
    findings: &[RuleFindingRecord],
    conflicts: &[ConflictGroupRecord],
    analysis_groups: &[CrossAgentAnalysisGroup],
    diagnostics: &[AdapterDiagnosticsRecord],
    taxonomy: &CapabilityTaxonomyResult,
    task_readiness: Option<&TaskReadinessResult>,
    route_ranking: Option<&SkillRouteRankingResult>,
    stale_drift: &StaleDriftDetectionResult,
    similar: &SimilarSkillGroupingResult,
) -> Vec<WorkspaceReadinessChecklistRow> {
    let mut rows = Vec::new();
    let visible_count = visible_details.len();
    let enabled_count = visible_details.iter().filter(|skill| skill.enabled).count();
    let project_count = visible_details
        .iter()
        .filter(|skill| skill.scope == Scope::AgentProject.as_str())
        .count();
    let coverage_score = if taxonomy.summary.domain_count == 0 {
        0
    } else {
        taxonomy
            .coverage_rows
            .iter()
            .map(|row| usize::from(row.coverage_score))
            .sum::<usize>()
            .checked_div(taxonomy.coverage_rows.len().max(1))
            .unwrap_or(0)
            .min(100) as u8
    };
    rows.push(WorkspaceReadinessChecklistRow {
        id: "workspace-readiness-capability-coverage".to_string(),
        category: "capability_coverage",
        status: workspace_status_for_score(coverage_score),
        score: coverage_score,
        title: "Capability coverage".to_string(),
        detail: format!(
            "{} capability domain(s) are visible across {} local skill(s).",
            taxonomy.summary.domain_count, visible_count
        ),
        agent: filters.agent.clone(),
        capability: None,
        evidence_refs: taxonomy
            .coverage_rows
            .iter()
            .flat_map(|row| row.evidence_refs.iter().cloned())
            .take(8)
            .collect(),
    });

    let enabled_score = enabled_count
        .checked_mul(100)
        .and_then(|score| score.checked_div(visible_count))
        .unwrap_or(0)
        .min(100) as u8;
    rows.push(WorkspaceReadinessChecklistRow {
        id: "workspace-readiness-enabled-scope".to_string(),
        category: "enabled_scoped_state",
        status: workspace_status_for_score(enabled_score),
        score: enabled_score,
        title: "Enabled and scoped skills".to_string(),
        detail: format!(
            "{} of {} visible skill(s) are enabled; {} are project-scoped.",
            enabled_count, visible_count, project_count
        ),
        agent: filters.agent.clone(),
        capability: None,
        evidence_refs: Vec::new(),
    });

    let blocking_finding_count = findings
        .iter()
        .filter(|finding| matches!(finding.effective_severity.as_str(), "critical" | "error"))
        .count();
    let risk_score = (100i16
        - (blocking_finding_count as i16 * 18).min(54)
        - (conflicts.len() as i16 * 16).min(32)
        - (analysis_groups.len() as i16 * 4).min(20))
    .clamp(0, 100) as u8;
    rows.push(WorkspaceReadinessChecklistRow {
        id: "workspace-readiness-risk-findings".to_string(),
        category: "risk_finding_state",
        status: workspace_status_for_score(risk_score),
        score: risk_score,
        title: "Risk and finding state".to_string(),
        detail: format!(
            "{} blocking finding(s), {} same-agent conflict(s), and {} cross-agent analysis group(s) are visible.",
            blocking_finding_count,
            conflicts.len(),
            analysis_groups.len()
        ),
        agent: filters.agent.clone(),
        capability: None,
        evidence_refs: Vec::new(),
    });

    let stale_score = (100i16
        - (stale_drift.summary.high_risk_count as i16 * 20).min(60)
        - (stale_drift.summary.medium_risk_count as i16 * 10).min(30)
        - (stale_drift.summary.drift_count as i16 * 6).min(24))
    .clamp(0, 100) as u8;
    rows.push(WorkspaceReadinessChecklistRow {
        id: "workspace-readiness-stale-drift".to_string(),
        category: "stale_drift",
        status: workspace_status_for_score(stale_score),
        score: stale_score,
        title: "Stale and drift signals".to_string(),
        detail: format!(
            "{} stale/drift row(s), {} high-risk row(s), and {} drift signal(s) were derived locally.",
            stale_drift.summary.returned_row_count,
            stale_drift.summary.high_risk_count,
            stale_drift.summary.drift_count
        ),
        agent: filters.agent.clone(),
        capability: None,
        evidence_refs: stale_drift
            .stale_drift_rows
            .iter()
            .flat_map(|row| row.evidence_refs.iter().cloned())
            .take(8)
            .collect(),
    });

    let ambiguity_count = similar.summary.routing_ambiguity_count
        + route_ranking
            .map(|ranking| ranking.ambiguity_warnings.len())
            .unwrap_or(0);
    let ambiguity_score = (100i16 - (ambiguity_count as i16 * 18).min(72)).clamp(0, 100) as u8;
    rows.push(WorkspaceReadinessChecklistRow {
        id: "workspace-readiness-routing-ambiguity".to_string(),
        category: "routing_ambiguity",
        status: workspace_status_for_score(ambiguity_score),
        score: ambiguity_score,
        title: "Routing ambiguity".to_string(),
        detail: format!(
            "{} similar-skill group(s) and {} routing ambiguity signal(s) are visible.",
            similar.summary.returned_group_count, ambiguity_count
        ),
        agent: filters.agent.clone(),
        capability: None,
        evidence_refs: similar
            .groups
            .iter()
            .flat_map(|group| group.evidence_refs.iter().cloned())
            .take(8)
            .collect(),
    });

    let blocked_adapter_count = diagnostics
        .iter()
        .filter(|diagnostic| {
            diagnostic.status == "blocked" || diagnostic.access.writable_status == "blocked"
        })
        .count();
    let adapter_score = (100i16 - (blocked_adapter_count as i16 * 12).min(60)).clamp(0, 100) as u8;
    rows.push(WorkspaceReadinessChecklistRow {
        id: "workspace-readiness-adapter-capability".to_string(),
        category: "adapter_capability",
        status: workspace_status_for_score(adapter_score),
        score: adapter_score,
        title: "Adapter capability".to_string(),
        detail: format!(
            "{} adapter diagnostic row(s) are available; {} have blocked status.",
            diagnostics.len(),
            blocked_adapter_count
        ),
        agent: filters.agent.clone(),
        capability: None,
        evidence_refs: Vec::new(),
    });

    if let Some(readiness) = task_readiness {
        rows.push(WorkspaceReadinessChecklistRow {
            id: "workspace-readiness-task-fit".to_string(),
            category: "task_fit",
            status: workspace_status_for_score(readiness.score),
            score: readiness.score,
            title: "Task readiness".to_string(),
            detail: readiness.summary.clone(),
            agent: filters.agent.clone(),
            capability: None,
            evidence_refs: readiness
                .candidate_skills
                .iter()
                .flat_map(|candidate| candidate.evidence_refs.iter().cloned())
                .take(8)
                .collect(),
        });
    }

    rows.sort_by(|left, right| {
        workspace_status_rank(left.status)
            .cmp(&workspace_status_rank(right.status))
            .then_with(|| left.score.cmp(&right.score))
            .then_with(|| left.category.cmp(right.category))
    });
    rows
}

fn workspace_status_rank(status: &str) -> u8 {
    match status {
        "blocked" => 0,
        "partial" => 1,
        "ready" => 2,
        _ => 3,
    }
}

fn workspace_agent_rows_from_comparison(
    comparison: &AgentReadinessComparisonResult,
    visible_details: &[SkillDetailRecord],
    diagnostics: &[AdapterDiagnosticsRecord],
) -> Vec<WorkspaceReadinessAgentRow> {
    comparison
        .agent_rows
        .iter()
        .map(|row| {
            let diagnostic = diagnostics
                .iter()
                .find(|diagnostic| diagnostic.agent == row.agent);
            let visible_skill_count = visible_details
                .iter()
                .filter(|skill| skill.agent == row.agent)
                .count();
            let enabled_skill_count = visible_details
                .iter()
                .filter(|skill| skill.agent == row.agent && skill.enabled)
                .count();
            let project_skill_count = visible_details
                .iter()
                .filter(|skill| {
                    skill.agent == row.agent && skill.scope == Scope::AgentProject.as_str()
                })
                .count();
            WorkspaceReadinessAgentRow {
                agent: row.agent.clone(),
                display_name: row.display_name.clone(),
                status: workspace_status_for_score(row.comparison_score),
                score: row.comparison_score,
                visible_skill_count,
                enabled_skill_count,
                project_skill_count,
                best_candidate: row.best_candidate.clone(),
                adapter_status: diagnostic.map(|diagnostic| diagnostic.status.to_string()),
                writable_status: diagnostic
                    .map(|diagnostic| diagnostic.access.writable_status.to_string()),
                install_status: diagnostic
                    .map(|diagnostic| diagnostic.access.install_status.to_string()),
                gap_count: row.gap_count,
                blocker_count: row.blocker_count,
                notes: row
                    .gap_notes
                    .iter()
                    .chain(row.blocker_notes.iter())
                    .take(8)
                    .cloned()
                    .collect(),
                evidence_refs: row.evidence_refs.clone(),
            }
        })
        .collect()
}

fn workspace_agent_rows_from_catalog(
    visible_details: &[SkillDetailRecord],
    diagnostics: &[AdapterDiagnosticsRecord],
    agent_filter: Option<&str>,
) -> Vec<WorkspaceReadinessAgentRow> {
    let mut agents = visible_details
        .iter()
        .filter_map(|skill| normalize_agent_label(&skill.agent))
        .collect::<BTreeSet<_>>();
    for diagnostic in diagnostics {
        if agent_matches(agent_filter, Some(diagnostic.agent)) {
            agents.insert(diagnostic.agent.to_string());
        }
    }
    agents
        .into_iter()
        .filter(|agent| agent_matches(agent_filter, Some(agent.as_str())))
        .map(|agent| {
            let diagnostic = diagnostics
                .iter()
                .find(|diagnostic| diagnostic.agent == agent);
            let visible_skill_count = visible_details
                .iter()
                .filter(|skill| skill.agent == agent)
                .count();
            let enabled_skill_count = visible_details
                .iter()
                .filter(|skill| skill.agent == agent && skill.enabled)
                .count();
            let project_skill_count = visible_details
                .iter()
                .filter(|skill| skill.agent == agent && skill.scope == Scope::AgentProject.as_str())
                .count();
            let enabled_portion = enabled_skill_count
                .checked_mul(45)
                .and_then(|score| score.checked_div(visible_skill_count))
                .unwrap_or(0)
                .min(45) as i16;
            let mut score = if visible_skill_count == 0 {
                0i16
            } else {
                35 + enabled_portion + (project_skill_count.min(2) as i16 * 5)
            };
            if diagnostic
                .map(|diagnostic| diagnostic.status == "blocked")
                .unwrap_or(false)
            {
                score -= 25;
            }
            let score = score.clamp(0, 100) as u8;
            let mut notes = Vec::new();
            if visible_skill_count == 0 {
                notes.push("No visible skills were found for this agent.".to_string());
            }
            if enabled_skill_count < visible_skill_count {
                notes.push(format!(
                    "{} of {} visible skill(s) are disabled.",
                    visible_skill_count.saturating_sub(enabled_skill_count),
                    visible_skill_count
                ));
            }
            if let Some(diagnostic) = diagnostic {
                notes.push(format!(
                    "Adapter diagnostics status={}, writable_status={}, install_status={}.",
                    diagnostic.status,
                    diagnostic.access.writable_status,
                    diagnostic.access.install_status
                ));
            }
            WorkspaceReadinessAgentRow {
                agent: agent.clone(),
                display_name: agent_readiness_display_name(&agent),
                status: workspace_status_for_score(score),
                score,
                visible_skill_count,
                enabled_skill_count,
                project_skill_count,
                best_candidate: None,
                adapter_status: diagnostic.map(|diagnostic| diagnostic.status.to_string()),
                writable_status: diagnostic
                    .map(|diagnostic| diagnostic.access.writable_status.to_string()),
                install_status: diagnostic
                    .map(|diagnostic| diagnostic.access.install_status.to_string()),
                gap_count: usize::from(visible_skill_count == 0),
                blocker_count: usize::from(score < 45),
                notes,
                evidence_refs: Vec::new(),
            }
        })
        .collect()
}

struct WorkspaceReadinessSummaryInput<'a> {
    project_root: Option<&'a Path>,
    visible_details: &'a [SkillDetailRecord],
    taxonomy: &'a CapabilityTaxonomyResult,
    readiness_rows: &'a [WorkspaceReadinessChecklistRow],
    agent_rows: &'a [WorkspaceReadinessAgentRow],
    capability_rows: &'a [WorkspaceReadinessCapabilityRow],
    gap_notes: &'a [String],
    blocker_notes: &'a [String],
}

fn workspace_readiness_summary(
    input: WorkspaceReadinessSummaryInput<'_>,
) -> WorkspaceReadinessSummary {
    let agent_count = input
        .visible_details
        .iter()
        .filter_map(|skill| normalize_agent_label(&skill.agent))
        .collect::<BTreeSet<_>>()
        .len()
        .max(input.agent_rows.len());
    let visible_skill_count = input.visible_details.len();
    let enabled_skill_count = input
        .visible_details
        .iter()
        .filter(|skill| skill.enabled)
        .count();
    let statuses = input
        .readiness_rows
        .iter()
        .map(|row| row.status)
        .chain(input.agent_rows.iter().map(|row| row.status))
        .chain(input.capability_rows.iter().map(|row| row.status))
        .collect::<Vec<_>>();
    let (ready_count, partial_count, blocked_count) = workspace_status_counts(statuses);
    let project_available = input.project_root.is_some()
        || input
            .visible_details
            .iter()
            .any(|skill| skill.scope == Scope::AgentProject.as_str());
    let summary = if visible_skill_count == 0 {
        "Workspace readiness is blocked because no visible local skills matched the selected workspace filters."
            .to_string()
    } else if blocked_count > 0 {
        format!(
            "Workspace readiness is partial: {} visible skill(s), {} capability row(s), and {} blocker row(s) need review.",
            visible_skill_count,
            input.capability_rows.len(),
            blocked_count
        )
    } else {
        format!(
            "Workspace readiness is ready across {} visible skill(s), {} agent(s), and {} capability row(s).",
            visible_skill_count,
            agent_count,
            input.capability_rows.len()
        )
    };
    WorkspaceReadinessSummary {
        workspace_available: visible_skill_count > 0,
        project_available,
        visible_skill_count,
        enabled_skill_count,
        agent_count,
        domain_count: input.taxonomy.summary.domain_count,
        capability_count: input.capability_rows.len(),
        ready_count,
        partial_count,
        blocked_count,
        gap_count: input.gap_notes.len(),
        blocker_count: input.blocker_notes.len(),
        summary,
    }
}

fn remediation_plan_safety_flags() -> RemediationPlanSafetyFlags {
    agent_readiness_safety_flags()
}

fn remediation_preview_drafts_safety_flags() -> RemediationPreviewDraftsSafetyFlags {
    agent_readiness_safety_flags()
}

fn remediation_preview_impact_safety_flags() -> RemediationPreviewImpactSafetyFlags {
    agent_readiness_safety_flags()
}

fn remediation_batch_review_safety_flags() -> RemediationBatchReviewSafetyFlags {
    agent_readiness_safety_flags()
}

fn remediation_plan_filters(
    params: &RemediationPlanParams,
    redaction_roots: &[(String, &'static str)],
) -> RemediationPlanFilters {
    let mut focus_areas = Vec::new();
    if let Some(focus) = params.focus.as_deref() {
        focus_areas.extend(
            focus
                .split([',', ';'])
                .filter_map(normalize_remediation_focus),
        );
    }
    focus_areas.extend(
        params
            .focus_areas
            .iter()
            .filter_map(|focus| normalize_remediation_focus(focus)),
    );
    focus_areas.sort();
    focus_areas.dedup();
    let mut candidate_instance_ids = params
        .candidate_instance_ids
        .iter()
        .map(|value| redact_for_llm_preview(value.trim()))
        .filter(|value| !value.is_empty())
        .collect::<Vec<_>>();
    candidate_instance_ids.sort();
    candidate_instance_ids.dedup();

    RemediationPlanFilters {
        agent: params.agent.as_deref().and_then(normalize_agent_label),
        task: params
            .task
            .as_deref()
            .map(str::trim)
            .filter(|task| !task.is_empty())
            .map(redact_for_llm_preview),
        project_root: params
            .project_root
            .as_deref()
            .map(str::trim)
            .filter(|path| !path.is_empty())
            .map(|path| redact_string(&redact_for_llm_preview(path), redaction_roots)),
        focus_areas,
        limit: params.limit.unwrap_or(12).clamp(1, 50),
        candidate_instance_ids,
        include_deferred: params.include_deferred,
    }
}

fn normalize_remediation_focus(focus: &str) -> Option<String> {
    let normalized = focus.trim().to_ascii_lowercase().replace(['_', ' '], "-");
    let canonical = match normalized.as_str() {
        "" => return None,
        "finding" | "findings" | "rule" | "rules" => "finding",
        "gap" | "gaps" | "coverage" | "capability-gap" => "gap",
        "ambiguity" | "routing" | "routing-ambiguity" | "conflict" | "conflicts" => "ambiguity",
        "drift" | "stale" | "stale-drift" => "drift",
        "readiness" | "workspace" | "workspace-readiness" | "task-readiness" => "readiness",
        "policy" | "cleanup" | "queue" => "policy",
        other => other,
    };
    Some(canonical.to_string())
}

fn empty_remediation_plan_result(
    filters: RemediationPlanFilters,
    catalog_available: bool,
) -> RemediationPlanResult {
    RemediationPlanResult {
        generated_by: "deterministic-service",
        catalog_available,
        filters,
        summary: RemediationPlanSummary {
            total_item_count: 0,
            returned_item_count: 0,
            high_priority_count: 0,
            medium_priority_count: 0,
            low_priority_count: 0,
            deferred_count: 0,
            finding_item_count: 0,
            gap_item_count: 0,
            ambiguity_item_count: 0,
            drift_item_count: 0,
            readiness_item_count: 0,
            policy_item_count: 0,
            blocker_count: 1,
            summary:
                "No local catalog is available, so remediation planning has no evidence."
                    .to_string(),
        },
        plan_items: Vec::new(),
        priority_rows: Vec::new(),
        gap_notes: vec![
            "Run a local scan before relying on remediation planning.".to_string(),
        ],
        blocker_notes: vec![
            "No provider request was sent and no fallback network lookup was attempted."
                .to_string(),
        ],
        evidence_references: Vec::new(),
        prompt_request: RemediationPlanPromptRequest {
            available: false,
            preview_method: "llm.previewPrompt",
            confirm_method: "llm.confirmPromptAndSend",
            action: "remediation_plan",
            request: LlmPreviewPromptParams {
                action: LlmPromptActionKind::RemediationPlan,
                profile_id: None,
                app_language: None,
                skill_instance_id: None,
                instance_ids: Vec::new(),
                analysis_kind: None,
                user_intent: Some(
                    "Explain deterministic remediation plan items using only local catalog evidence."
                        .to_string(),
                ),
            },
            note: "Prompt preview is unavailable until local catalog evidence exists.".to_string(),
        },
        safety_flags: remediation_plan_safety_flags(),
    }
}

struct RemediationItemInput {
    category: &'static str,
    priority_score: u8,
    severity: &'static str,
    title: String,
    summary: String,
    detail: String,
    affected_agent: Option<String>,
    affected_skill: Option<RemediationAffectedSkill>,
    affected_capability: Option<String>,
    affected_task: Option<String>,
    affected_instance_ids: Vec<String>,
    suggested_safe_next_action: String,
    prerequisites: Vec<String>,
    blockers: Vec<String>,
    deferred: bool,
    evidence_refs: Vec<String>,
}

fn remediation_item(input: RemediationItemInput) -> RemediationPlanItem {
    let mut affected_instance_ids = input
        .affected_instance_ids
        .into_iter()
        .map(|id| redact_for_llm_preview(&id))
        .collect::<Vec<_>>();
    affected_instance_ids.sort();
    affected_instance_ids.dedup();
    let id = stable_remediation_item_id(
        input.category,
        &input.title,
        &affected_instance_ids,
        &input.evidence_refs,
    );
    RemediationPlanItem {
        id,
        rank: 0,
        priority: remediation_priority_for_score(input.priority_score),
        severity: input.severity,
        category: input.category,
        title: input.title,
        summary: input.summary,
        detail: input.detail,
        affected_agent: input.affected_agent,
        affected_skill: input.affected_skill,
        affected_capability: input.affected_capability,
        affected_task: input.affected_task,
        affected_instance_ids,
        suggested_safe_next_action: input.suggested_safe_next_action,
        prerequisites: input.prerequisites,
        blockers: input.blockers,
        deferred: input.deferred,
        evidence_refs: input.evidence_refs,
        side_effect_flags: remediation_side_effect_flags(),
        safety_flags: remediation_plan_safety_flags(),
    }
}

fn remediation_insert_evidence(
    evidence_by_id: &mut BTreeMap<String, TaskReadinessEvidenceReference>,
    source_type: &'static str,
    source_id: &str,
    label: String,
    severity: Option<String>,
    related_instance_id: Option<String>,
) -> String {
    let id = format!("{source_type}:{source_id}");
    evidence_by_id
        .entry(id.clone())
        .or_insert_with(|| TaskReadinessEvidenceReference {
            id: id.clone(),
            source_type,
            source_id: redact_for_llm_preview(source_id),
            label,
            severity,
            related_instance_id,
        });
    id
}

fn remediation_affected_skill(skill: &SkillDetailRecord) -> RemediationAffectedSkill {
    RemediationAffectedSkill {
        instance_id: skill.id.clone(),
        definition_id: skill.definition_id.clone(),
        skill_name: redact_for_llm_preview(&skill.name),
        agent: skill.agent.clone(),
        scope: skill.scope.clone(),
        enabled: skill.enabled,
        state: skill.state.clone(),
    }
}

fn remediation_related_instances_for_finding(
    finding: &RuleFindingRecord,
    visible_skill_ids: &BTreeSet<&str>,
) -> Vec<String> {
    finding
        .instance_id
        .iter()
        .filter(|id| visible_skill_ids.contains(id.as_str()))
        .cloned()
        .collect()
}

fn remediation_matches_filter(
    filters: &RemediationPlanFilters,
    instance_id: Option<&str>,
    affected_instance_ids: &[String],
) -> bool {
    let id_matches = filters.candidate_instance_ids.is_empty()
        || instance_id.is_some_and(|id| {
            filters
                .candidate_instance_ids
                .iter()
                .any(|candidate| candidate == id)
        })
        || affected_instance_ids.iter().any(|id| {
            filters
                .candidate_instance_ids
                .iter()
                .any(|candidate| candidate == id)
        });
    id_matches
}

fn remediation_focus_matches(filters: &RemediationPlanFilters, category: &str) -> bool {
    filters.focus_areas.is_empty()
        || filters
            .focus_areas
            .iter()
            .any(|focus| focus == category || (focus == "readiness" && category == "gap"))
}

fn remediation_score_for_severity(severity: &str) -> u8 {
    match severity {
        "critical" => 100,
        "error" => 90,
        "warning" | "warn" => 72,
        "info" => 42,
        _ => 35,
    }
}

fn remediation_score_for_priority(priority: &str) -> u8 {
    match priority {
        "high" => 86,
        "medium" => 62,
        "low" => 34,
        _ => 30,
    }
}

fn remediation_priority_for_score(score: u8) -> &'static str {
    match score {
        75..=100 => "high",
        45..=74 => "medium",
        _ => "low",
    }
}

fn remediation_severity(severity: &str) -> &'static str {
    match severity {
        "critical" => "critical",
        "error" => "error",
        "warning" | "warn" => "warning",
        "info" => "info",
        _ => "info",
    }
}

fn remediation_blockers_for_finding(finding: &RuleFindingRecord) -> Vec<String> {
    let mut blockers = Vec::new();
    if matches!(finding.effective_severity.as_str(), "critical" | "error") {
        blockers.push("High-severity local finding requires human review.".to_string());
    }
    if finding.suppressed {
        blockers.push("Finding is suppressed; verify suppression before acting.".to_string());
    }
    if !matches!(finding.triage_status.as_str(), "open" | "needs-follow-up") {
        blockers.push(format!(
            "Finding triage status is `{}`.",
            redact_for_llm_preview(&finding.triage_status)
        ));
    }
    blockers
}

fn remediation_side_effect_flags() -> Vec<&'static str> {
    vec![
        "provider_request_sent=false",
        "write_back_allowed=false",
        "write_actions_available=false",
        "skill_files_mutated=false",
        "agent_config_mutated=false",
        "script_execution_allowed=false",
        "snapshot_created=false",
        "triage_mutation_allowed=false",
        "credential_accessed=false",
        "cloud_sync_performed=false",
        "telemetry_emitted=false",
    ]
}

fn stable_remediation_item_id(
    category: &str,
    title: &str,
    affected_instance_ids: &[String],
    evidence_refs: &[String],
) -> String {
    let mut hasher = Sha256::new();
    hasher.update(category.as_bytes());
    hasher.update(b"\0");
    hasher.update(title.as_bytes());
    hasher.update(b"\0");
    for id in affected_instance_ids {
        hasher.update(id.as_bytes());
        hasher.update(b"\0");
    }
    for evidence in evidence_refs {
        hasher.update(evidence.as_bytes());
        hasher.update(b"\0");
    }
    let digest = hasher.finalize();
    format!("remediation-{}", hex_prefix(&digest, 12))
}

fn remediation_sorted_items(
    mut items: Vec<RemediationPlanItem>,
    filters: &RemediationPlanFilters,
) -> Vec<RemediationPlanItem> {
    items.retain(|item| filters.include_deferred || !item.deferred);
    items.retain(|item| remediation_focus_matches(filters, item.category));
    items.sort_by(|left, right| {
        remediation_priority_rank(left.priority)
            .cmp(&remediation_priority_rank(right.priority))
            .then_with(|| {
                severity_rank_for_queue(left.severity).cmp(&severity_rank_for_queue(right.severity))
            })
            .then_with(|| left.deferred.cmp(&right.deferred))
            .then_with(|| left.category.cmp(right.category))
            .then_with(|| left.title.cmp(&right.title))
            .then_with(|| left.id.cmp(&right.id))
    });
    items.truncate(filters.limit);
    for (index, item) in items.iter_mut().enumerate() {
        item.rank = index + 1;
    }
    items
}

fn remediation_priority_rank(priority: &str) -> u8 {
    match priority {
        "high" => 0,
        "medium" => 1,
        "low" => 2,
        _ => 3,
    }
}

fn remediation_plan_summary(
    total_item_count: usize,
    returned_item_count: usize,
    items: &[RemediationPlanItem],
) -> RemediationPlanSummary {
    let high_priority_count = items.iter().filter(|item| item.priority == "high").count();
    let medium_priority_count = items
        .iter()
        .filter(|item| item.priority == "medium")
        .count();
    let low_priority_count = items.iter().filter(|item| item.priority == "low").count();
    let deferred_count = items.iter().filter(|item| item.deferred).count();
    let category_count = |category: &str| {
        items
            .iter()
            .filter(|item| item.category == category)
            .count()
    };
    let blocker_count = items.iter().map(|item| item.blockers.len()).sum();
    let summary = if returned_item_count == 0 {
        "No remediation plan items matched the selected local filters.".to_string()
    } else {
        format!(
            "Remediation planner returned {returned_item_count} of {total_item_count} local read-only item(s): {high_priority_count} high, {medium_priority_count} medium, {low_priority_count} low."
        )
    };
    RemediationPlanSummary {
        total_item_count,
        returned_item_count,
        high_priority_count,
        medium_priority_count,
        low_priority_count,
        deferred_count,
        finding_item_count: category_count("finding"),
        gap_item_count: category_count("gap"),
        ambiguity_item_count: category_count("ambiguity"),
        drift_item_count: category_count("drift"),
        readiness_item_count: category_count("readiness"),
        policy_item_count: category_count("policy"),
        blocker_count,
        summary,
    }
}

fn remediation_priority_rows(items: &[RemediationPlanItem]) -> Vec<RemediationPriorityRow> {
    let mut rows = Vec::new();
    for priority in ["high", "medium", "low"] {
        let matching = items
            .iter()
            .filter(|item| item.priority == priority)
            .collect::<Vec<_>>();
        if matching.is_empty() {
            continue;
        }
        let mut category_counts = BTreeMap::new();
        for item in &matching {
            *category_counts
                .entry(item.category.to_string())
                .or_insert(0) += 1;
        }
        rows.push(RemediationPriorityRow {
            priority,
            severity: matching
                .iter()
                .map(|item| item.severity)
                .min_by_key(|severity| severity_rank_for_queue(severity))
                .unwrap_or("info"),
            item_count: matching.len(),
            category_counts,
            top_item_ids: matching
                .iter()
                .take(5)
                .map(|item| item.id.clone())
                .collect(),
        });
    }
    rows
}

fn remediation_preview_drafts_filters(
    params: &RemediationPreviewDraftsParams,
    redaction_roots: &[(String, &'static str)],
) -> RemediationPreviewDraftsFilters {
    let mut skill_ids = params
        .skill_ids
        .iter()
        .map(|value| redact_for_llm_preview(value.trim()))
        .filter(|value| !value.is_empty())
        .collect::<Vec<_>>();
    skill_ids.sort();
    skill_ids.dedup();
    let mut finding_ids = params
        .finding_ids
        .iter()
        .map(|value| redact_for_llm_preview(value.trim()))
        .filter(|value| !value.is_empty())
        .collect::<Vec<_>>();
    finding_ids.sort();
    finding_ids.dedup();
    let mut draft_types = params
        .draft_types
        .iter()
        .filter_map(|value| normalize_remediation_draft_type(value))
        .collect::<Vec<_>>();
    draft_types.sort();
    draft_types.dedup();
    RemediationPreviewDraftsFilters {
        agent: params.agent.as_deref().and_then(normalize_agent_label),
        task: params
            .task
            .as_deref()
            .map(str::trim)
            .filter(|task| !task.is_empty())
            .map(|task| redact_string(&redact_for_llm_preview(task), redaction_roots)),
        skill_ids,
        finding_ids,
        draft_types,
        limit: params.limit.unwrap_or(12).clamp(1, 50),
        include_policy_drafts: params.include_policy_drafts,
    }
}

fn normalize_remediation_draft_type(value: &str) -> Option<String> {
    let normalized = value.trim().to_ascii_lowercase().replace(['_', ' '], "-");
    let canonical = match normalized.as_str() {
        "" => return None,
        "frontmatter" | "metadata" | "yaml" => "frontmatter",
        "description" | "body" | "summary" => "description",
        "permissions" | "permission" | "allowed-tools" | "tool" | "tools" => "permissions",
        "dependency" | "dependencies" | "dep" | "deps" => "dependency",
        "policy" | "governance" | "routing-policy" => "policy",
        other => other,
    };
    Some(canonical.to_string())
}

fn remediation_preview_draft_type_matches(
    filters: &RemediationPreviewDraftsFilters,
    draft_type: &str,
) -> bool {
    filters.draft_types.is_empty() || filters.draft_types.iter().any(|value| value == draft_type)
}

